import{_ as l,o as e,c as n,ag as r}from"./chunks/framework.DXGyWiRo.js";const s="/images/uebung072.jpg",t="/images/uebung073.jpg",c=JSON.parse('{"title":"Übung Lektion 44","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung44.md","filePath":"lektionen/uebung44.md"}'),o={name:"lektionen/uebung44.md"};function p(P,i,a,m,g,u){return e(),n("div",null,[...i[0]||(i[0]=[r('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-44" tabindex="-1">Übung Lektion 44 <a class="header-anchor" href="#ubung-lektion-44" aria-label="Permalink to &quot;Übung Lektion 44&quot;">​</a></h1><p>A) Bestimmen und übersetzen Sie folgende Formen:</p><ol><li>आदेः । आदि m. Gen.Abl.sg.m.</li><li>आदः । अद् 2P Impf.2.sg.P</li><li>अपुनाः । पू 9U Impf.2.sg.P</li><li>पुनः । पुनर् &quot;wiederum, aber&quot;</li><li>आसीः । अस् 2P Impf.2.sg.P</li><li>आसि । आस् 2Ā Impf.1.sg.Ā</li><li>तन्वीथाः । तन् 8U Opt.2.sg.Ā</li><li>अध्यैथाः । अधि-इ 2Ā Impf.2.sg.Ā</li><li>वित्थ । विद् 2P Ind.Präs.2.pl.P</li><li>वीतम् । वि-इ 2 PPP.Nom.Akk.sg.n.Akk.sg.m.</li><li>आध्वम् । आस् 2Ā Impf.2.pl.Ā</li><li>पाथ । पा 2P Ind.Präs.2.pl.P</li><li>कथम् । &quot;wie?&quot;</li><li>स्वपिषि । स्वप् 2P Ind.Präs.2.sg.P</li><li>अश्नीयात । अश् 9P Opt.2.pl.P</li><li>आश्नाः । अश् 9P Impf.2.sg.P</li><li>आश्नुवत । अश् 5Ā Ind.Präs.2.pl.Ā</li><li>यन्ति । इ 2P Ind.Präs.2.pl.P ; Part.Präs.P.Nom.Akk.pl.n.</li><li>यथा । या 2P Ind.Präs.2.pl.P</li><li>यथा । &quot;wie&quot;</li><li>इयात । इ 2P Opt.2.pl.P</li><li>शिष्ठ । शास् 2P Ind.Präs.2.pl.P</li><li>शिष्टः । शास् 2P PPP.Nom.sg.m.</li><li>आध्वे । आस् 2Ā Ind.Präs.2.pl.Ā</li><li>अवक् । वच् 2P Impf.2.3.sg.P</li><li>स्थ । अस् 2P Ind.Präs.2.pl.P</li><li>तस्थौ । स्था 1P Perf IV.1.3.sg.P</li><li>बध्नीथ । बन्ध् 9P Ind.Präs.2.pl.P</li><li>अशिष्ट । शास् 2P Impf.2.pl.P</li><li>धुक्षे । दुह् 2U Ind.Präs.2.sg.Ā</li><li>धोक्ष्ये । दुह् 2U Fut.1.sg.Ā</li><li>वध्वे । वस् 2Ā Ind.Präs.2.pl.Ā</li><li>अहन् । हन् 2P Impf.2.3.sg.P</li><li>आख्येयम् । आ-ख्या 2 Gerundiv.Nom.Akk.sg.n.Akk.sg.m.</li><li>वदेयम् । वद् 1P Opt.1.sg.P</li><li>यामः । या 2P Ind.Präs.1.pl.P</li><li>येमिम । यम् 1P Perf. Vc.1.pl.P</li><li>शेरते । शी 2Ā Ind.Präs.3.pl.Ā</li><li>द्विषीथाः । द्विष् 2U Opt.2.sg.Ā</li><li>कुरुथ । कृ 8U Ind.Pr.2.pl.P</li><li>आप्नुत । आप् 5P Impf.2.pl.P</li><li>विक्रीणीध्वम् । वि-क्री 9Ā Opt.2.pl.Ā</li><li>सुन्मः । सु 5U Ind.Präs.1.pl.P</li><li>रोदिषि । रुद् 2P Ind.Präs.2.sg.P</li><li>अस्तवीः । स्तु 2U Impf.2.sg.P</li><li>अशृणुत । श्रु 5P Impf.2.pl.P</li><li>ब्रुवीध्वम् । ब्रू 2U Opt.2.pl.Ā</li><li>द्विड्ढ्वे । द्विष् 2U Ind.Präs.2.pl.Ā</li><li>शेकुः । शक् 5P Perf. Vb 3.pl.P</li><li>चिनुथ । चि 5U Ind.Präs.2.pl.P</li><li>हथ । हन् 2P Ind.Präs.2.pl.P</li><li>हतः । हन् 2P PPP.Nom.sg.m.</li></ol><p>B) Übersetzen Sie:</p><p>अक्रोधेन जयेत्क्रोधमसाधुं सधुना जयेज्जयेत्सत्येन चानृतम् ॥१॥</p><blockquote><p>Durch Nichtzorn besiege man den Zorn, durch das Gute besiege man den Unguten, durch Wahrheit besiege man die Unwahrheit.</p></blockquote><p>पुत्राः किं पितृभ्यः पिण्डान्प्रायच्छत ॥२॥</p><blockquote><p>Söhne, habt ihr den Ahnvätern Reisbällchen gegeben?</p></blockquote><p>कानि शास्त्राणि काश्यामध्यैथाः ॥३॥</p><blockquote><p>Welche Lehrwerke hast Du in Benares studiert?</p></blockquote><p>बुद्धपुत्राश्चेन्महाशयनेषु शयीरन्प्रव्रज्यायां कृतं व्रतं न चरेयुः ॥४॥</p><blockquote><p>Wenn die Söhne Buddhas (= Mönche) auf großen Betten lägen, würden sie das bei der Ordination zum Novizen gegebene Gelübde nicht einhalten.</p></blockquote><p>अप्यार्ययुद्धाख्यानमाख्यास्यन्तं गुरुमभ्यनन्दः ॥५॥</p><blockquote><p>Hast du auch den Dichter, der die Erzählung von den edlen Kriegern vortragen wird, willkommen geheißen?</p></blockquote><p>द्वेष्यमपि न द्विष्यात लोभनीयं च न लुभ्येतैवं च प्रसन्ना भविष्यथ ॥६॥</p><blockquote><p>Ihr sollt Hassenswertes nicht hassen und Begehrenswertes nicht begehren, so werdet ihr abgeklärt werden.</p></blockquote><p>न योत्स्य इत्यर्जुन उवाच ॥७॥</p><blockquote><p>Arjuna sagte, dass er nicht kämpfen werde.</p></blockquote><p>अशोच्यानशोचः प्रज्ञावादांश्च प्रवक्तुमैच्छः ।<br> मृताञ्जीवतश्च बुद्धिमन्तो न शोचन्ति ॥८॥</p><blockquote><p>Du hast Nicht-Betrauernswerte betrauert und wolltest Worte der Weisheit verkünden. Einsichtige betrauern weder Tote noch Lebendige.</p></blockquote><p><img src="'+s+'" alt=""><br> Abb.: मृताञ्जीवतश्च बुद्धिमन्तो न शोचन्ति<br> वाराणसी<br> [Bildquelle: Sgt.Steiner. -- <a href="http://www.flickr.com/photos/42114936@N00/279731957/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/42114936@N00/279731957/</a>. -- Zugriff am 2009-01-22. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><p>Bestimmen Sie folgende Formen:</p><ol><li>वदिता । वदितृ Nom.sg.m.</li><li>उदिता । वद् PPP Nom.sg.f.</li><li>धातुः । धातृ Gen.Abl.sg.m. ; धातु m. Nom.sg.m.</li><li>दधुः । धा 3U Perf. IV.3.pl.P</li><li>अदधुः । धा 3U Impf.3.pl.P</li><li>दध्युः । धा Opt.3.pl.P</li><li>रक्षामि । रक्ष् 1P Ind.Präs.1.sg.P</li><li>रक्षाणि । रक्ष 3 &quot;beschützend&quot; Nom.Akk.Vok.pl.n.</li><li>रक्षीणि । रक्षिन् 3 Nom.Akk.Vok.pl.n.</li><li>रक्षिणी । रक्षिण् Nom.sg.f.</li><li>राजनि । राजन् m. Lok.sg.m.</li><li>आसि । आस् 2Ā Impf.1.sg.Ā</li><li>इज्ये । यज् 1U Pass.Präs.1.sg. ; Gerundiv.Lok.sg.m.n.Vok.sg.f.</li><li>अयुध्ये । युध् 4Ā Impf.1.sg.Ā</li><li>अयोध्ये । युध् 4Ā Gerundiv + अ Lok.sg.m.Vok.sg.f. ; Kaus.Pass.Impf.1.sg.</li><li>अयोधये । युध् 4Ā Kaus.Impf.1.sg.</li><li>शोचनीयायाम् । शुच् 1P Gerundiv.Lok.sg.f.</li><li>वर्त्स्यति । वृत् 1Ā Fut.3.sg.P</li><li>आसन् । अस् 1P Impf.3.pl.P</li><li>असन् । अस् 1P Part.Präs.P + अ Nom.sg.m.</li><li>बिभ्यति । भी 3P Ind.Präs.3.pl.P</li><li>कुत्र । &quot;wo&quot;</li><li>चेरिम । चर् 1P Perf. Vb.1.pl.P</li><li>योक्ष्ये । युज् 7U Fut.1.sg.Ā</li><li>योज्ये । युज् 7U Gerundiv.Lok.sg.m.n.</li><li>युज्ये । युज् 7U Pass.Präs.1.sg.</li><li>चिक्ये । चि 5U Perf.1.3.sg.Ā</li><li>अजायामहि । जन् 4Ā Impf.1.pl.Ā</li><li>स्मर्येय । स्मृ 1P Pass.Opt.1.sg. ; Kaus.Pass.Opt.1.sg.</li><li>स्मर्याय । स्मृ 1P Gerundiv.Dat.sg.m.n.</li><li>कया । किम् 3 Instr.sg.f.</li><li>क्रेया । क्री 9U Gerundiv.Nom.sg.f.</li><li>आत्मने । आत्मन् m. Dat.sg.m.</li><li>अदानम् । अ-दान n. Nom.Akk.sg.n.</li><li>आददानम् । आ-दा 3Ā Part.Präs.Ā.Nom.Akk.sg.n.Akk.sg.m.</li><li>सेदिम । सद् 1P Perf. Vb.1.pl.P.</li><li>क्व । &quot;wo?&quot;</li><li>पिपूर्मः । पॄ 3P Ind.Präs.1.pl.P</li><li>कैः । किम् 3 Instr.pl.m.n.</li><li>कृत्येन । कृ 8U Gerundiv.Instr.sg.m.n.</li></ol><p><img src="'+t+'" alt=""><br> Abb.: वदिता<br> Hari S. Bhartia, Co-Chairman and Managing Director, Jubilant Organosys, India, World Economic Forum&#39;s India Economic Summit 2008 in New Delhi<br> [Bildquelle: World Economic Forum. -- <a href="http://www.flickr.com/photos/worldeconomicforum/3038333212/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/worldeconomicforum/3038333212/</a>. -- Zugriff am 2009-01-22. -- <a href="http://creativecommons.org/licenses/by-sa/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, share alike)]</p>',25)])])}const k=l(o,[["render",p]]);export{c as __pageData,k as default};
